"use strict";(self.webpackChunkdocu=self.webpackChunkdocu||[]).push([[955],{7801:(e,t,a)=>{a.r(t),a.d(t,{assets:()=>l,contentTitle:()=>r,default:()=>c,frontMatter:()=>s,metadata:()=>n,toc:()=>h});const n=JSON.parse('{"id":"book exports/cryptocrackup","title":"Crypto Crackup: Sam Bankman-Fried, FTX, and SBF\'s Weird Island Empire","description":"- One of the earliest traits Trabucco would recall about Sam is that he appeared to almost \u201cbarely\u201d sleep while at camp, a habit he seems to have maintained into adulthood","source":"@site/docs/book exports/cryptocrackup.md","sourceDirName":"book exports","slug":"/book exports/cryptocrackup","permalink":"/docs/book exports/cryptocrackup","draft":false,"unlisted":false,"editUrl":"https://github.com/bippyboppy/doc/docs/book exports/cryptocrackup.md","tags":[],"version":"current","frontMatter":{},"sidebar":"tutorialSidebar","previous":{"title":"Pure Land","permalink":"/docs/book exports/buddhism/pureland"},"next":{"title":"Doing Good Better: How Effective Altruism Can Help You Make a Difference","permalink":"/docs/book exports/doinggoodbetter"}}');var i=a(4848),o=a(8453);const s={},r="Crypto Crackup: Sam Bankman-Fried, FTX, and SBF's Weird Island Empire",l={},h=[];function d(e){const t={h1:"h1",header:"header",li:"li",p:"p",ul:"ul",...(0,o.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(t.header,{children:(0,i.jsx)(t.h1,{id:"crypto-crackup-sam-bankman-fried-ftx-and-sbfs-weird-island-empire",children:"Crypto Crackup: Sam Bankman-Fried, FTX, and SBF's Weird Island Empire"})}),"\n",(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"One of the earliest traits Trabucco would recall about Sam is that he appeared to almost \u201cbarely\u201d sleep while at camp, a habit he seems to have maintained into adulthood"}),"\n"]}),"\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"For Bentham, though, it was simpler: If something causes pleasure, it\u2019s good, and if something causes pain, it\u2019s bad"}),"\n"]}),"\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"Sam would later repeat the following sentiment across multiple interviews: \u201cThere\u2019s a chicken tortured for five weeks on a factory farm, and you spend half an hour eating it. That was hard for me to justify.\u201d126"}),"\n"]}),"\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"one night at the end of his freshman year, he was eating tofu for dinner and his friend asked, \u201cHey, Sam, are you vegetarian now?\u201d He said, \u201cYes,\u201d even though he had eaten a cheeseburger for lunch that day\u2014but he never ate meat again, Sam told the 80,000 Hours podcast.131 \u201cI had to reframe myself in my own mind as someone who didn\u2019t eat meat.\u201d Then it was easy.132"}),"\n"]}),"\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"Though the first EAs met in a modest university basement over humble hummus sandwiches, the group now has perks and $28 million per year in funding, its own offices, a gym, weekly yoga classes, catering, and a nap room (quantitatively speaking, the increased productivity after a ten-minute nap redeems the ten lost minutes"}),"\n"]}),"\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"The internship was designed to train the inexperienced interns in trading strategies and tactics. Interns took classes on coding, machine learning, and even poker, and in mock trading classes they played games that simulated trading options"}),"\n"]}),"\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"If Ellison is indeed the worldoptimization blogger, she spent an inordinate amount of time writing about books she had read\u2014everything from romances to science fiction, to business books, to mystery novels, to biographies. And like Sam, the worldoptimization blogger felt that her parents, for all their intelligence, failed to \u201ctake ideas seriously.\u201d"}),"\n"]}),"\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"In order to best serve the altruistic causes that he was so passionate about, Sam would practice a version of a philosophy called \u201crisk neutrality,\u201d a concept that effective altruists built upon in their work.224 Risk neutrality means focusing on the expected gain of an investment after adjusting for risk\u2014even if the risks are high."}),"\n"]}),"\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"Different definitions of risk neutrality exist in the wild, but the general spirit of Sam\u2019s version of risk neutrality seems to be this: aggressive risk taking is a good thing, and not being aggressive enough about taking risk for the causes you care about is a bad thing\u2014particularly in the context of \u201cearning to give.\u201d2"}),"\n"]}),"\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"To illustrate risk neutrality, consider a hypothetical situation with two investment options: one which involves a guaranteed payoff of $100, while the other involves a gamble, with a 50% chance of a $200 payoff and a 50% chance you receive nothing. In our hypothetical scenario, the risk neutral investor would be indifferent between the two options, as the expected value (EV) in both cases equals $100. 1. EV = 100% probability X $100 = $100 2. EV = (50% probability X $200) + (50% probability X $0) = $100 + 0 = $100 However, a risk-averse investor would introduce the added variable of risk into their decision, thereby unbalancing the alternatives above."}),"\n"]}),"\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"I think there are really compelling reasons to think that the \u2018optimal strategy\u2019 to follow is one that probably fails\u2014but if it doesn\u2019t fail, it\u2019s great. But as [an effective-altruism] community, what that would imply is this weird thing where you almost celebrate cases where someone completely craps out\u2014where things end up nowhere close to what they could have been\u2014because that\u2019s what the majority of well-played strategies should end with. I don\u2019t think that we recognize that enough as [an effective-altruism] community, and I think there are lots of specific instances as well where we don\u2019t incentivize that.368"}),"\n"]}),"\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"It was during a poker game with friends in Shanghai in 2013 that CZ first heard about Bitcoin.434 CZ didn\u2019t know what it was at the time, but once he began to learn about it, he was hooked on the idea.435 According to crypto news outlet Decrypt, Zhao acted swiftly, selling his house for $1 million and investing that money to buy bitcoin for $600 apiece. (At the time of this writing, one bitcoin is selling for approximately $30,000; the price can change dramatically due to high volatility.)436 A few years later, CZ launched his own crypto exchange, Binance, which is now the largest in the world, with multibillion-dollar daily trading volumes.437"}),"\n"]}),"\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"Sam suggested that ignoring Covid altogether would actually have been a better response than the current one. He wrote, \u201c~1% of the population would have lost ~8 years of life, and another ~30% would have lost ~1 week to sickness. That would have averaged to about 30 days per person, which is frankly a fair bit better than 1.5 years of lockdown + massive inflation + also we\u2019re not done yet"}),"\n"]}),"\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"Sam didn\u2019t enjoy them very often. He lived like a \u201ccapitalist monk,\u201d we were told again and again by the press.596 The number of journalists and interviewers who exclaimed, He drives a Corolla!!, during this period\u2014as if that proved his virtue\u2014are too numerous to count.597 \u201cYou pretty quickly run out of really effective ways to make yourself happier by spending money,\u201d Sam told Bloomberg among other news outlets. \u201cI don\u2019t want a yacht.\u201d598"}),"\n"]}),"\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"Sam was well suited to this kind of role. He loved hectic days with back-to-back meetings, he told The Generalist, noting, \u201cmost of life lives in the margins.\u201d619 At this point, Sam was sleeping as little as two hours per night, taking sporadic naps only when he keeled over from exhaustion. Sam said that he had suffered from insomnia since he was a teenager, so his sleeping habits during that time period may not have been entirely unfamiliar to him"}),"\n"]}),"\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"If the company did, in fact, know and present the numbers correctly, the second step was to compare the two sides of the ledger: assets and liabilities. Sam said he believed the most salvageable situation was that in which assets and liabilities were about equal. \u201cFor a relatively small potential incineration of money, we can resolve that problem and make them able to continue operating and carry on and not cause contagion or customers losing assets,\u201d he told Levine.877"}),"\n"]}),"\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"Ultimately, Sam agreed with Piper\u2019s characterization that he was \u201creally good at talking about ethics, for someone who kind of saw it all as a game with winners and losers.\u201d1395 Sam replied that he \u201chad to be\u201d because ethics are what \u201creputations are made of,\u201d even in the corporate world.1396 He called the whole situation a \u201cdumb game we woke westerners play where we say all the right shiboleths [sic] and so everyone likes us.\u201d1397"}),"\n",(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsx)(t.li,{children:"ethics as a game"}),"\n"]}),"\n"]}),"\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"Something that struck Tiffany Fong as particularly jarring in her initial conversation with Sam was when she asked him what he would miss most in prison. His answer would puzzle Fong. \u201cDo you mean what things I would miss rationally or viscerally?\u201d Sam asked her. \u201cAnd I was like, \u2018What?\u2019\u201d she said. \u201cHe classified them as if they\u2019re completely separate buckets. I don\u2019t think about things that way. He\u2019s very compartmentalized.\u201d1737"}),"\n"]}),"\n"]})]})}function c(e={}){const{wrapper:t}={...(0,o.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(d,{...e})}):d(e)}},8453:(e,t,a)=>{a.d(t,{R:()=>s,x:()=>r});var n=a(6540);const i={},o=n.createContext(i);function s(e){const t=n.useContext(o);return n.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:s(e.components),n.createElement(o.Provider,{value:t},e.children)}}}]);